    #[test]
    fn cancel_cast_during_target_selection_returns_to_priority() {
        use crate::game::engine::apply_as_current;
        use crate::types::actions::GameAction;

        let mut state = setup_game_at_main_phase();
        let obj_id = create_instant_in_hand(&mut state, PlayerId(0));
        add_mana(&mut state, PlayerId(0), ManaType::Red, 1);

        // Create two creatures so targeting is ambiguous (not auto-targeted)
        for card_id_val in [50, 51] {
            let cid = create_object(
                &mut state,
                CardId(card_id_val),
                PlayerId(1),
                "Goblin".to_string(),
                Zone::Battlefield,
            );
            state
                .objects
                .get_mut(&cid)
                .unwrap()
                .card_types
                .core_types
                .push(CoreType::Creature);
        }

        // Cast the spell -> should enter TargetSelection
        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: obj_id,
                card_id: CardId(10),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(
            result.waiting_for,
            WaitingFor::TargetSelection { .. }
        ));
        // CR 601.2a: The spell is announced onto the stack at the start of
        // the cast. The object's own zone stays at the origin until finalize
        // so mid-cast continuous effects (graveyard escape, cast-from-exile
        // filters, etc.) keep evaluating correctly.
        assert_eq!(state.stack.len(), 1);
        assert_eq!(state.stack[0].id, obj_id);
        assert!(!state.players[0].hand.is_empty());

        // CR 601.2i: Cancel -> the placeholder stack entry is popped and the
        // card remains in hand (no zone revert needed because no zone change
        // has been committed yet).
        let result = apply_as_current(&mut state, GameAction::CancelCast).unwrap();
        assert!(matches!(result.waiting_for, WaitingFor::Priority { .. }));
        assert!(state.stack.is_empty());
        assert!(!state.players[0].hand.is_empty());
        assert!(state.players[0].hand.contains(&obj_id));
    }

    /// CR 601.2a: After announcement, the spell is the topmost object on the
    /// stack and remains there through each interactive cast step. This test
    /// exercises the stack-at-announcement invariant during TargetSelection.
    #[test]
    fn spell_is_on_stack_during_target_selection() {
        use crate::game::engine::apply_as_current;
        use crate::types::actions::GameAction;

        let mut state = setup_game_at_main_phase();
        let obj_id = create_instant_in_hand(&mut state, PlayerId(0));
        add_mana(&mut state, PlayerId(0), ManaType::Red, 1);

        // Two ambiguous targets force interactive selection.
        for card_id_val in [50, 51] {
            let cid = create_object(
                &mut state,
                CardId(card_id_val),
                PlayerId(1),
                "Goblin".to_string(),
                Zone::Battlefield,
            );
            state
                .objects
                .get_mut(&cid)
                .unwrap()
                .card_types
                .core_types
                .push(CoreType::Creature);
        }

        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: obj_id,
                card_id: CardId(10),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(
            result.waiting_for,
            WaitingFor::TargetSelection { .. }
        ));

        // CR 601.2a: The StackEntry exists from announcement — no ghost-entry
        // synthesis is needed on the client side.
        assert_eq!(state.stack.len(), 1);
        let entry = &state.stack[0];
        assert_eq!(entry.id, obj_id);
        assert_eq!(entry.controller, PlayerId(0));
        // CR 601.2i: The placeholder entry has no ability attached yet —
        // `finalize_cast` fills it in after costs commit.
        match &entry.kind {
            StackEntryKind::Spell {
                card_id,
                ability,
                actual_mana_spent,
                ..
            } => {
                assert_eq!(*card_id, CardId(10));
                assert!(ability.is_none());
                assert_eq!(*actual_mana_spent, 0);
            }
            other => panic!("expected Spell stack entry, got {:?}", other),
        }
    }

    /// CR 601.2i: Cancelling from `ManaPayment` pops the placeholder stack
    /// entry pushed at announcement. Exercises the Convoke path which keeps
    /// the PendingCast on outer `GameState::pending_cast`.
    #[test]
    fn cancel_cast_from_mana_payment_pops_stack_entry() {
        use crate::game::engine::apply_as_current;
        use crate::types::actions::GameAction;

        let mut state = setup_game_at_main_phase();

        // A convoke-eligible creature on the battlefield gates the convoke
        // flow into ManaPayment (without one, convoke_mode is filtered away
        // and the flow goes straight to finalize_cast).
        let creature_id = create_object(
            &mut state,
            CardId(59),
            PlayerId(0),
            "Token".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&creature_id).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
            obj.has_summoning_sickness = false;
        }

        let obj_id = create_object(
            &mut state,
            CardId(60),
            PlayerId(0),
            "Convoke Spell".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&obj_id).unwrap();
            obj.card_types.core_types.push(CoreType::Sorcery);
            obj.keywords.push(Keyword::Convoke);
            obj.mana_cost = ManaCost::Cost {
                shards: vec![],
                generic: 2,
            };
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Draw {
                    count: QuantityExpr::Fixed { value: 1 },
                    target: TargetFilter::Controller,
                },
            ));
        }
        add_mana(&mut state, PlayerId(0), ManaType::Colorless, 2);

        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: obj_id,
                card_id: CardId(60),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(result.waiting_for, WaitingFor::ManaPayment { .. }));
        assert_eq!(state.stack.len(), 1);
        assert!(state.pending_cast.is_some());

        let result = apply_as_current(&mut state, GameAction::CancelCast).unwrap();
        assert!(matches!(result.waiting_for, WaitingFor::Priority { .. }));
        assert!(state.stack.is_empty());
        assert!(state.pending_cast.is_none());
        assert!(state.players[0].hand.contains(&obj_id));
    }

    #[test]
    fn convoke_payment_records_creatures_that_convoked_spell() {
        use crate::game::engine::apply_as_current;

        let mut state = setup_game_at_main_phase();

        let helper = create_object(
            &mut state,
            CardId(61),
            PlayerId(0),
            "Helper".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&helper).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
        }

        let obj_id = create_object(
            &mut state,
            CardId(62),
            PlayerId(0),
            "Convoke Creature".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&obj_id).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
            obj.keywords.push(Keyword::Convoke);
            obj.mana_cost = ManaCost::Cost {
                shards: vec![],
                generic: 1,
            };
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Unimplemented {
                    name: "Creature".to_string(),
                    description: None,
                },
            ));
        }

        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: obj_id,
                card_id: CardId(62),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(result.waiting_for, WaitingFor::ManaPayment { .. }));

        let result = apply_as_current(
            &mut state,
            GameAction::TapForConvoke {
                object_id: helper,
                mana_type: ManaType::Colorless,
            },
        )
        .unwrap();
        assert!(
            result
                .events
                .iter()
                .all(|event| !matches!(event, GameEvent::ManaAdded { .. })),
            "convoke pays instead of adding mana"
        );
        let result = apply_as_current(&mut state, GameAction::PassPriority).unwrap();
        assert!(
            result
                .events
                .iter()
                .all(|event| !matches!(event, GameEvent::ManaExpended { .. })),
            "convoke payments are not mana spent"
        );
        assert!(matches!(
            state.stack.last().map(|entry| &entry.kind),
            Some(StackEntryKind::Spell {
                actual_mana_spent: 0,
                ..
            })
        ));

        let obj = state.objects.get(&obj_id).unwrap();
        assert_eq!(obj.convoked_creatures, vec![helper]);
        assert!(!obj.mana_spent_to_cast);
        assert_eq!(obj.mana_spent_to_cast_amount, 0);
        assert_eq!(obj.colors_spent_to_cast.distinct_colors(), 0);
    }

    /// Issue #1589 — "cannot activate the convoke ability." The frontend
    /// dispatches convoke taps from the engine's per-object legal-action surface
    /// (`legal_actions_full`'s `legal_actions_by_object`, NOT the flat list,
    /// which omits mana actions). After casting a Convoke spell the engine is in
    /// `ManaPayment { convoke_mode: Some(Convoke) }`, and every convoke-eligible
    /// creature you control MUST appear there with a `TapForConvoke` action —
    /// otherwise the player has no UI affordance to activate convoke.
    #[test]
    fn convoke_creature_exposed_in_legal_actions_during_payment() {
        let mut state = setup_game_at_main_phase();

        let helper = create_object(
            &mut state,
            CardId(61),
            PlayerId(0),
            "Helper".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&helper).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
        }

        let obj_id = create_object(
            &mut state,
            CardId(62),
            PlayerId(0),
            "Convoke Creature".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&obj_id).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
            obj.keywords.push(Keyword::Convoke);
            obj.mana_cost = ManaCost::Cost {
                shards: vec![],
                generic: 1,
            };
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Unimplemented {
                    name: "Creature".to_string(),
                    description: None,
                },
            ));
        }

        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: obj_id,
                card_id: CardId(62),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(
            result.waiting_for,
            WaitingFor::ManaPayment {
                convoke_mode: Some(ConvokeMode::Convoke),
                ..
            }
        ));

        // The per-object legal-action surface the frontend renders against must
        // offer the convoke creature a TapForConvoke action.
        let (_flat, _costs, grouped) = crate::ai_support::legal_actions_full(&state);
        let helper_actions = grouped.get(&helper).cloned().unwrap_or_default();
        assert!(
            helper_actions.iter().any(|action| matches!(
                action,
                GameAction::TapForConvoke { object_id, .. } if *object_id == helper
            )),
            "legal_actions_full must expose TapForConvoke for the convoke-eligible \
             creature during ManaPayment, got {helper_actions:?}"
        );
    }

