    #[test]
    fn convoke_payment_offers_and_accepts_colored_creature_payment() {
        use crate::game::engine::apply_as_current;

        let mut state = setup_game_at_main_phase();

        let creature = create_object(
            &mut state,
            CardId(63),
            PlayerId(0),
            "Green Helper".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&creature).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
            obj.color.push(ManaColor::Green);
        }

        let artifact = create_object(
            &mut state,
            CardId(64),
            PlayerId(0),
            "Artifact Helper".to_string(),
            Zone::Battlefield,
        );
        state
            .objects
            .get_mut(&artifact)
            .unwrap()
            .card_types
            .core_types
            .push(CoreType::Artifact);

        let spell = create_object(
            &mut state,
            CardId(65),
            PlayerId(0),
            "Convoke Spell".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&spell).unwrap();
            obj.card_types.core_types.push(CoreType::Sorcery);
            obj.keywords.push(Keyword::Convoke);
            obj.mana_cost = ManaCost::Cost {
                shards: vec![ManaCostShard::Green],
                generic: 0,
            };
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Draw {
                    count: QuantityExpr::Fixed { value: 1 },
                    target: TargetFilter::Controller,
                },
            ));
        }

        let result = apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: spell,
                card_id: CardId(65),
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .unwrap();
        assert!(matches!(
            result.waiting_for,
            WaitingFor::ManaPayment {
                convoke_mode: Some(ConvokeMode::Convoke),
                ..
            }
        ));

        let (_, _, grouped) = crate::ai_support::legal_actions_full(&state);
        assert!(grouped
            .get(&creature)
            .is_some_and(|actions| actions.iter().any(|action| matches!(
                action,
                GameAction::TapForConvoke {
                    object_id,
                    mana_type: ManaType::Green
                } if *object_id == creature
            ))));
        assert!(
            grouped.get(&artifact).is_none_or(|actions| actions
                .iter()
                .all(|action| !matches!(action, GameAction::TapForConvoke { .. }))),
            "artifacts must not be offered for convoke payment"
        );

        let rejected = apply_as_current(
            &mut state,
            GameAction::TapForConvoke {
                object_id: artifact,
                mana_type: ManaType::Colorless,
            },
        );
        assert!(
            rejected.is_err(),
            "artifacts must not be accepted for convoke payment"
        );

        let result = apply_as_current(
            &mut state,
            GameAction::TapForConvoke {
                object_id: creature,
                mana_type: ManaType::Green,
            },
        )
        .unwrap();
        assert!(
            result
                .events
                .iter()
                .all(|event| !matches!(event, GameEvent::ManaAdded { .. })),
            "colored convoke payment must not add mana"
        );
        apply_as_current(&mut state, GameAction::PassPriority).unwrap();

        let obj = state.objects.get(&spell).unwrap();
        assert_eq!(obj.convoked_creatures, vec![creature]);
        assert!(!obj.mana_spent_to_cast);
        assert_eq!(obj.colors_spent_to_cast.distinct_colors(), 0);
    }

    // --- Aura casting tests ---
    // Note: `ControllerRef` + `TargetFilter` are already imported at the test module
    // head (where the CantBeActivated tests need them). No local re-import required.

    /// Create an Aura enchantment in hand with Enchant creature keyword.
    fn create_aura_in_hand(state: &mut GameState, player: PlayerId) -> ObjectId {
        let obj_id = create_object(
            state,
            CardId(30),
            player,
            "Pacifism".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&obj_id).unwrap();
            obj.card_types.core_types.push(CoreType::Enchantment);
            obj.card_types.subtypes.push("Aura".to_string());
            obj.keywords.push(Keyword::Enchant(TargetFilter::Typed(
                TypedFilter::creature(),
            )));
            obj.mana_cost = ManaCost::Cost {
                shards: vec![ManaCostShard::White],
                generic: 0,
            };
        }
        obj_id
    }

    #[test]
    fn aura_with_multiple_targets_returns_target_selection() {
        let mut state = setup_game_at_main_phase();
        let aura = create_aura_in_hand(&mut state, PlayerId(0));
        add_mana(&mut state, PlayerId(0), ManaType::White, 1);

        // Create two creatures as potential targets
        for card_id_val in [50, 51] {
            let cid = create_object(
                &mut state,
                CardId(card_id_val),
                PlayerId(1),
                "Goblin".to_string(),
                Zone::Battlefield,
            );
            state
                .objects
                .get_mut(&cid)
                .unwrap()
                .card_types
                .core_types
                .push(CoreType::Creature);
        }

        let mut events = Vec::new();
        let result =
            handle_cast_spell(&mut state, PlayerId(0), aura, CardId(30), &mut events).unwrap();

        match result {
            WaitingFor::TargetSelection { target_slots, .. } => {
                assert_eq!(target_slots.len(), 1);
                assert_eq!(target_slots[0].legal_targets.len(), 2);
            }
            other => panic!("Expected TargetSelection, got {:?}", other),
        }
    }

    #[test]
    fn aura_with_single_target_auto_targets() {
        let mut state = setup_game_at_main_phase();
        let aura = create_aura_in_hand(&mut state, PlayerId(0));
        add_mana(&mut state, PlayerId(0), ManaType::White, 1);

        // Create one creature as the only target
        let creature = create_object(
            &mut state,
            CardId(50),
            PlayerId(1),
            "Goblin".to_string(),
            Zone::Battlefield,
        );
        state
            .objects
            .get_mut(&creature)
            .unwrap()
            .card_types
            .core_types
            .push(CoreType::Creature);

        let mut events = Vec::new();
        let result =
            handle_cast_spell(&mut state, PlayerId(0), aura, CardId(30), &mut events).unwrap();

        // Should auto-target and go straight to Priority (on stack)
        assert!(matches!(result, WaitingFor::Priority { .. }));
        assert_eq!(state.stack.len(), 1);
        // Verify the target was recorded on the stack entry
        if let StackEntryKind::Spell {
            ability: Some(ability),
            ..
        } = &state.stack[0].kind
        {
            assert_eq!(
                ability.targets,
                vec![crate::types::ability::TargetRef::Object(creature)]
            );
        } else {
            panic!("Expected spell with ability on stack");
        }
    }

