    /// CR 101.2 + CR 601.3a: Angelic Arbiter — "Each opponent who attacked with a
    /// creature this turn can't cast spells." The per-affected-player turn-activity
    /// predicate must gate the cast-lock: an opponent who has NOT attacked this turn
    /// can still cast. This discriminates the prior misparse (an unconditional
    /// opponent cast-lock that wrongly blocked, e.g., Bolt Bend).
    #[test]
    fn angelic_arbiter_cast_lock_only_after_opponent_attacks() {
        let mut state = setup_game_at_main_phase();
        // Opponent-controlled (PlayerId(1)) Angelic Arbiter clause on the battlefield.
        let arbiter = create_object(
            &mut state,
            CardId(901),
            PlayerId(1),
            "Angelic Arbiter".to_string(),
            Zone::Battlefield,
        );
        let def = parse_static_line(
            "Each opponent who attacked with a creature this turn can't cast spells.",
        )
        .unwrap();
        assert_eq!(
            def.per_player_condition,
            Some(crate::types::ability::ParsedCondition::YouAttackedThisTurn)
        );
        state
            .objects
            .get_mut(&arbiter)
            .unwrap()
            .static_definitions
            .push(def);

        // Player 0's spell on the stack (CantBeCast has no `affected` filter, so any
        // spell object is restricted).
        let spell = create_object(
            &mut state,
            CardId(902),
            PlayerId(0),
            "Bolt Bend".to_string(),
            Zone::Stack,
        );
        let spell_obj = state.objects.get(&spell).unwrap().clone();

        // Player 0 has NOT attacked this turn -> the per-player gate fails -> NOT
        // blocked. On main (unconditional lock) this assertion FAILS.
        assert!(
            !is_blocked_by_cant_be_cast(&state, PlayerId(0), &spell_obj),
            "an opponent who has not attacked this turn must still be able to cast"
        );

        // Record that player 0 attacked this turn -> the per-player gate holds ->
        // now blocked (CR 601.3a).
        state.players_attacked_this_turn.insert(PlayerId(0));
        assert!(
            is_blocked_by_cant_be_cast(&state, PlayerId(0), &spell_obj),
            "after attacking, the opponent can no longer cast spells"
        );
    }

    // --- PerTurnCastLimit enforcement tests ---

    fn add_per_turn_cast_limit_permanent(
        state: &mut GameState,
        controller: PlayerId,
        who: ProhibitionScope,
        max: u32,
        spell_filter: Option<TargetFilter>,
    ) -> ObjectId {
        let id = create_object(
            state,
            CardId(state.next_object_id),
            controller,
            "Limiter".to_string(),
            Zone::Battlefield,
        );
        state
            .objects
            .get_mut(&id)
            .unwrap()
            .static_definitions
            .push(StaticDefinition::new(StaticMode::PerTurnCastLimit {
                who,
                max,
                spell_filter,
            }));
        id
    }

    fn make_spell_obj(state: &mut GameState, controller: PlayerId, is_creature: bool) -> ObjectId {
        use crate::types::card_type::CoreType;
        let id = create_object(
            state,
            CardId(state.next_object_id),
            controller,
            "Test Spell".to_string(),
            Zone::Hand,
        );
        let obj = state.objects.get_mut(&id).unwrap();
        if is_creature {
            obj.card_types.core_types = vec![CoreType::Creature];
        } else {
            obj.card_types.core_types = vec![CoreType::Instant];
        }
        id
    }

    #[test]
    fn per_turn_limit_all_players_blocks_after_one_cast() {
        let mut state = setup_game_at_main_phase();
        add_per_turn_cast_limit_permanent(
            &mut state,
            PlayerId(0),
            ProhibitionScope::AllPlayers,
            1,
            None,
        );
        let spell_id = make_spell_obj(&mut state, PlayerId(0), false);

        // No spells cast yet — should NOT be blocked
        let obj = state.objects.get(&spell_id).unwrap();
        assert!(!is_blocked_by_per_turn_cast_limit(&state, PlayerId(0), obj));

        // Record one spell cast (clone to avoid borrow conflict)
        let obj_clone = state.objects.get(&spell_id).unwrap().clone();
        restrictions::record_spell_cast(
            &mut state,
            PlayerId(0),
            &obj_clone,
            CastingVariant::Normal,
        );

        // Now should be blocked
        let obj = state.objects.get(&spell_id).unwrap();
        assert!(is_blocked_by_per_turn_cast_limit(&state, PlayerId(0), obj));
    }

    #[test]
    fn per_turn_limit_controller_scope_blocks_only_controller() {
        let mut state = setup_game_at_main_phase();
        add_per_turn_cast_limit_permanent(
            &mut state,
            PlayerId(0),
            ProhibitionScope::Controller,
            1,
            None,
        );
        let spell_id = make_spell_obj(&mut state, PlayerId(0), false);

        let obj_clone = state.objects.get(&spell_id).unwrap().clone();
        restrictions::record_spell_cast(
            &mut state,
            PlayerId(0),
            &obj_clone,
            CastingVariant::Normal,
        );
        restrictions::record_spell_cast(
            &mut state,
            PlayerId(1),
            &obj_clone,
            CastingVariant::Normal,
        );

        let obj = state.objects.get(&spell_id).unwrap();
        // Controller (P0) should be blocked
        assert!(is_blocked_by_per_turn_cast_limit(&state, PlayerId(0), obj));
        // Opponent (P1) should NOT be blocked
        assert!(!is_blocked_by_per_turn_cast_limit(&state, PlayerId(1), obj));
    }

