    #[test]
    fn first_x_spell_reducer_uses_x_filter_dynamic_counter_count_and_first_gate() {
        let mut state = setup_game_at_main_phase();

        let reducer = create_object(
            &mut state,
            CardId(305),
            PlayerId(0),
            "Zimone, Infinite Analyst".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&reducer).unwrap();
            obj.counters.insert(CounterType::Plus1Plus1, 2);
            obj.static_definitions.push(
                parse_static_line(
                    "The first spell you cast with {X} in its mana cost each turn costs {1} less to cast for each +1/+1 counter on ~.",
                )
                .unwrap(),
            );
        }

        let non_x_spell = create_object(
            &mut state,
            CardId(306),
            PlayerId(0),
            "Non-X Spell".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&non_x_spell).unwrap();
            obj.card_types.core_types.push(CoreType::Sorcery);
            obj.mana_cost = ManaCost::generic(2);
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Unimplemented {
                    name: "Sorcery".to_string(),
                    description: None,
                },
            ));
        }

        assert!(
            !can_cast_object_now(&state, PlayerId(0), non_x_spell),
            "Zimone must not reduce non-X spells"
        );

        let x_spell = create_object(
            &mut state,
            CardId(307),
            PlayerId(0),
            "X Spell".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&x_spell).unwrap();
            obj.card_types.core_types.push(CoreType::Sorcery);
            obj.mana_cost = ManaCost::Cost {
                shards: vec![ManaCostShard::X],
                generic: 2,
            };
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Unimplemented {
                    name: "Sorcery".to_string(),
                    description: None,
                },
            ));
        }

        assert!(
            can_cast_object_now(&state, PlayerId(0), x_spell),
            "two +1/+1 counters should reduce the first X spell's generic cost by two"
        );

        state.spells_cast_this_turn_by_player.insert(
            PlayerId(0),
            crate::im::Vector::from(vec![crate::types::SpellCastRecord {
                name: "Earlier X Spell".to_string(),
                core_types: vec![CoreType::Sorcery],
                supertypes: vec![],
                subtypes: vec![],
                keywords: vec![],
                colors: vec![],
                mana_value: 2,
                has_x_in_cost: true,
                from_zone: Zone::Hand,
                cast_variant: crate::types::game_state::CastingVariant::Normal,
            }]),
        );

        assert!(
            !can_cast_object_now(&state, PlayerId(0), x_spell),
            "the reduction must stop after the first X spell each turn"
        );
    }

    #[test]
    fn opponent_first_noncreature_tax_uses_caster_history() {
        let mut state = setup_game_at_main_phase();
        state.active_player = PlayerId(1);
        state.priority_player = PlayerId(1);
        state.waiting_for = WaitingFor::Priority {
            player: PlayerId(1),
        };

        let tax_source = create_object(
            &mut state,
            CardId(308),
            PlayerId(0),
            "Heartwood Storyteller Avatar".to_string(),
            Zone::Battlefield,
        );
        state.objects.get_mut(&tax_source).unwrap().static_definitions.push(
            parse_static_line(
                "The first noncreature spell each opponent casts each turn costs {1} more to cast.",
            )
            .unwrap(),
        );

        add_mana(&mut state, PlayerId(1), ManaType::Colorless, 1);
        let spell = create_object(
            &mut state,
            CardId(309),
            PlayerId(1),
            "Opponent Instant".to_string(),
            Zone::Hand,
        );
        {
            let obj = state.objects.get_mut(&spell).unwrap();
            obj.card_types.core_types.push(CoreType::Instant);
            obj.mana_cost = ManaCost::generic(1);
            Arc::make_mut(&mut obj.abilities).push(AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::Unimplemented {
                    name: "Instant".to_string(),
                    description: None,
                },
            ));
        }

        assert!(
            !can_cast_object_now(&state, PlayerId(1), spell),
            "opponent's first noncreature spell should be taxed beyond one available mana"
        );

        state.spells_cast_this_turn_by_player.insert(
            PlayerId(1),
            crate::im::Vector::from(vec![crate::types::SpellCastRecord {
                name: "Earlier Instant".to_string(),
                core_types: vec![CoreType::Instant],
                supertypes: vec![],
                subtypes: vec![],
                keywords: vec![],
                colors: vec![],
                mana_value: 1,
                has_x_in_cost: false,
                from_zone: Zone::Hand,
                cast_variant: crate::types::game_state::CastingVariant::Normal,
            }]),
        );

        assert!(
            can_cast_object_now(&state, PlayerId(1), spell),
            "after that opponent has cast a noncreature spell this turn, the first-spell tax should no longer apply"
        );
    }

    #[test]
    fn spell_matches_cost_filter_fail_closed_for_unrecognized_variants() {
        let state = GameState::default();
        let spell_id = ObjectId(1);
        let source_id = ObjectId(2);

        // Recognized: Typed filter delegates to matches_target_filter
        assert!(!spell_matches_cost_filter(
            &state,
            PlayerId(0),
            spell_id,
            &TargetFilter::Typed(crate::types::ability::TypedFilter::creature()),
            source_id,
        ));

        // Unrecognized: None, Player, SelfRef all return false (fail-closed)
        assert!(!spell_matches_cost_filter(
            &state,
            PlayerId(0),
            spell_id,
            &TargetFilter::None,
            source_id,
        ));
        assert!(!spell_matches_cost_filter(
            &state,
            PlayerId(0),
            spell_id,
            &TargetFilter::Player,
            source_id,
        ));
        assert!(!spell_matches_cost_filter(
            &state,
            PlayerId(0),
            spell_id,
            &TargetFilter::SelfRef,
            source_id,
        ));
    }

    // -----------------------------------------------------------------------
    // Flashback (CR 702.34)
    // -----------------------------------------------------------------------

    /// Create an instant in the graveyard with Flashback.
    fn add_flashback_instant_to_graveyard(
        state: &mut GameState,
        player: PlayerId,
        flashback_cost: ManaCost,
        mana_cost: ManaCost,
    ) -> ObjectId {
        let card_id = CardId(state.next_object_id);
        let obj_id = create_object(
            state,
            card_id,
            player,
            "Think Twice".to_string(),
            Zone::Graveyard,
        );
        let obj = state.objects.get_mut(&obj_id).unwrap();
        obj.card_types.core_types.push(CoreType::Instant);
        obj.base_card_types = obj.card_types.clone();
        obj.mana_cost = mana_cost;
        obj.base_keywords
            .push(Keyword::Flashback(FlashbackCost::Mana(
                flashback_cost.clone(),
            )));
        obj.keywords = obj.base_keywords.clone();
        // Give it a simple draw effect so it has an ability to cast
        let ability = crate::types::ability::AbilityDefinition::new(
            crate::types::ability::AbilityKind::Spell,
            crate::types::ability::Effect::Draw {
                count: QuantityExpr::Fixed { value: 1 },
                target: crate::types::ability::TargetFilter::Controller,
            },
        );
        Arc::make_mut(&mut obj.abilities).push(ability.clone());
        Arc::make_mut(&mut obj.base_abilities).push(ability);
        obj_id
    }

    fn add_retrace_sorcery_to_graveyard(state: &mut GameState, player: PlayerId) -> ObjectId {
        let card_id = CardId(state.next_object_id);
        let obj_id = create_object(
            state,
            card_id,
            player,
            "Flame Jab".to_string(),
            Zone::Graveyard,
        );
        let obj = state.objects.get_mut(&obj_id).unwrap();
        obj.card_types.core_types.push(CoreType::Sorcery);
        obj.base_card_types = obj.card_types.clone();
        obj.mana_cost = ManaCost::Cost {
            shards: vec![ManaCostShard::Red],
            generic: 0,
        };
        obj.base_mana_cost = obj.mana_cost.clone();
        obj.base_keywords.push(Keyword::Retrace);
        obj.keywords = obj.base_keywords.clone();
        let ability = AbilityDefinition::new(
            AbilityKind::Spell,
            Effect::Unimplemented {
                name: "retrace test spell".to_string(),
                description: None,
            },
        );
        Arc::make_mut(&mut obj.abilities).push(ability.clone());
        Arc::make_mut(&mut obj.base_abilities).push(ability);
        obj_id
    }

    fn add_land_to_hand(state: &mut GameState, player: PlayerId, name: &str) -> ObjectId {
        let land_id = create_object(
            state,
            CardId(state.next_object_id),
            player,
            name.to_string(),
            Zone::Hand,
        );
        let obj = state.objects.get_mut(&land_id).unwrap();
        obj.card_types.core_types.push(CoreType::Land);
        obj.base_card_types = obj.card_types.clone();
        land_id
    }

