        obj.base_card_types = obj.card_types.clone();
        obj.mana_cost = ManaCost::Cost {
            shards: vec![ManaCostShard::Blue],
            generic: 0,
        };
        obj.base_mana_cost = obj.mana_cost.clone();
        obj.base_keywords.push(Keyword::JumpStart);
