    fn add_harmonize_draw_spell_to_graveyard(
        state: &mut GameState,
        player: PlayerId,
        card_id: CardId,
        name: &str,
    ) -> ObjectId {
        let spell = create_object(state, card_id, player, name.to_string(), Zone::Graveyard);
        {
            let obj = state.objects.get_mut(&spell).unwrap();
            obj.card_types.core_types.push(CoreType::Sorcery);
            obj.base_card_types = obj.card_types.clone();
            obj.mana_cost = ManaCost::Cost {
                shards: vec![ManaCostShard::Blue],
                generic: 2,
            };
            obj.base_keywords.push(Keyword::Harmonize(ManaCost::Cost {
                shards: vec![ManaCostShard::Blue],
                generic: 4,
            }));
            obj.keywords = obj.base_keywords.clone();
            let ability = crate::types::ability::AbilityDefinition::new(
                crate::types::ability::AbilityKind::Spell,
                crate::types::ability::Effect::Draw {
                    count: QuantityExpr::Fixed { value: 3 },
                    target: TargetFilter::Controller,
                },
            );
            Arc::make_mut(&mut obj.abilities).push(ability.clone());
            Arc::make_mut(&mut obj.base_abilities).push(ability);
        }
        spell
    }

    /// CR 702.180a (issue #1550): Winternight Stories — Harmonize {4}{U}. With
    /// only 4 mana but a 4-power creature to tap (reducing the {4} generic to
    /// {0}), the spell must be legally castable from the graveyard. Before the
    /// fix the castability check used the full {4}{U} cost and hid it.
    #[test]
    fn harmonize_card_castable_when_creature_tap_covers_generic() {
        let mut state = setup_game_at_main_phase();

        let spell = add_harmonize_draw_spell_to_graveyard(
            &mut state,
            PlayerId(0),
            CardId(77_000),
            "Winternight Stories",
        );

        // A 4-power untapped creature the player controls (the tap target).
        let creature = create_object(
            &mut state,
            CardId(77_001),
            PlayerId(0),
            "Power Four".to_string(),
            Zone::Battlefield,
        );
        {
            let c = state.objects.get_mut(&creature).unwrap();
            c.card_types.core_types.push(CoreType::Creature);
            c.power = Some(4);
            c.toughness = Some(4);
        }

        // Only 4 mana available — short of the full {4}{U} = 5.
        add_mana(&mut state, PlayerId(0), ManaType::Blue, 4);

        assert!(
            can_cast_object_now(&state, PlayerId(0), spell),
            "Harmonize {{4}}{{U}} must be castable with 4 mana + a 4-power creature to tap"
        );
    }

    /// CR 702.180a + CR 601.2h: A creature tapped for Harmonize's cost
    /// reduction is already tapped before the remaining mana is paid. If that
    /// same creature is the only available mana source for the remaining
    /// colored shard, the cast must not be offered as legally payable.
    #[test]
    fn harmonize_castability_does_not_reuse_tapped_reduction_creature_for_mana() {
        let mut state = setup_game_at_main_phase();

        let spell = add_harmonize_draw_spell_to_graveyard(
            &mut state,
            PlayerId(0),
            CardId(77_010),
            "Winternight Stories",
        );

        let creature = create_object(
            &mut state,
            CardId(77_011),
            PlayerId(0),
            "Blue Dork".to_string(),
            Zone::Battlefield,
        );
        {
            let obj = state.objects.get_mut(&creature).unwrap();
            obj.card_types.core_types.push(CoreType::Creature);
            obj.summoning_sick = false;
            obj.power = Some(4);
            obj.toughness = Some(4);
            Arc::make_mut(&mut obj.abilities).push(
                AbilityDefinition::new(
                    AbilityKind::Activated,
                    Effect::Mana {
                        produced: ManaProduction::Fixed {
                            colors: vec![ManaColor::Blue],
                            contribution: ManaContribution::Base,
                        },
                        restrictions: vec![],
                        grants: vec![],
                        expiry: None,
                        target: None,
                    },
                )
                .cost(AbilityCost::Tap),
            );
        }

        assert!(
            !can_cast_object_now(&state, PlayerId(0), spell),
            "the Harmonize reduction creature cannot also tap for the remaining {{U}}"
        );
    }

    #[test]
    fn echo_of_eons_flashback_castable_with_nonempty_hand() {
        let mut state = setup_game_at_main_phase();
        let echo_id = add_echo_of_eons_to_graveyard(&mut state);
        let echo_card_id = state.objects.get(&echo_id).unwrap().card_id;

        let hand_card = create_object(
            &mut state,
            CardId(9001),
            PlayerId(0),
            "Nonempty Hand Card".to_string(),
            Zone::Hand,
        );
        for i in 0..10 {
            create_object(
                &mut state,
                CardId(9100 + i),
                PlayerId(0),
                format!("P0 Library Card {i}"),
                Zone::Library,
            );
            create_object(
                &mut state,
                CardId(9200 + i),
                PlayerId(1),
                format!("P1 Library Card {i}"),
                Zone::Library,
            );
        }
        add_mana(&mut state, PlayerId(0), ManaType::Blue, 3);

        assert!(
            spell_objects_available_to_cast(&state, PlayerId(0)).contains(&echo_id),
            "Echo of Eons with flashback should be available from graveyard"
        );
        assert!(
            can_cast_object_now(&state, PlayerId(0), echo_id),
            "nonempty hand must not be treated as a cast-time target/choice blocker"
        );
        assert!(
            crate::ai_support::legal_actions(&state)
                .iter()
                .any(|action| {
                    matches!(
                        action,
                        GameAction::CastSpell { object_id, .. } if *object_id == echo_id
                    )
                }),
            "legal action generation should expose the flashback cast"
        );

        crate::game::engine::apply_as_current(
            &mut state,
            GameAction::CastSpell {
                object_id: echo_id,
                card_id: echo_card_id,
                targets: vec![],

                payment_mode: CastPaymentMode::Auto,
            },
        )
        .expect("Echo of Eons should cast via flashback");
        assert_eq!(state.stack.len(), 1);

        crate::game::engine::apply_as_current(&mut state, GameAction::PassPriority).unwrap();
        let resolution =
            crate::game::engine::apply_as_current(&mut state, GameAction::PassPriority)
                .expect("Echo of Eons should resolve");

        assert!(state.stack.is_empty());
        assert_eq!(state.objects.get(&echo_id).unwrap().zone, Zone::Exile);
        assert!(
            resolution.events.iter().any(|event| {
                matches!(
                    event,
                    GameEvent::ZoneChanged {
                        object_id,
                        from: Some(Zone::Hand),
                        to: Zone::Library,
                        ..
                    } if *object_id == hand_card
                )
            }),
            "the nonempty hand card should be shuffled into the library during resolution"
        );
        assert!(matches!(
            state.waiting_for,
            WaitingFor::Priority {
                player: PlayerId(0)
            } | WaitingFor::Priority {
                player: PlayerId(1)
            }
        ));
    }

